// PHASE 1: ENHANCED INGEST WITH SESSION MANAGEMENT - FIXED
// Validates input, retrieves historical state, prepares for EMA smoothing

// Handle both webhook ($json.body) and manual trigger ($json) inputs
const inputData = $json.body || $json || {};

// CRITICAL FIX: Handle empty session_id strings (not just undefined)
const rawSessionId = inputData.session_id || $json.session_id;
const sessionId = (rawSessionId && rawSessionId.trim()) ? rawSessionId : `session-${Date.now()}`;

// Debug logging
console.log('📥 RAW INPUT - $json keys:', Object.keys($json));
console.log('📥 inputData keys:', Object.keys(inputData));
console.log('📥 Raw session_id:', rawSessionId);
console.log('📥 Final session_id:', sessionId);
const messages = inputData.messages || [];
const evaluationMode = inputData.evaluation_mode || false;
const turnIndex = inputData.turn_index || 1;
const apiRequest = inputData.api_request || false;
const directMessage = inputData.message || '';

console.log('📥 ENHANCED INGEST - Session:', sessionId, 'Turn:', turnIndex);
console.log('🔗 API Request:', apiRequest);
console.log('📝 Messages count:', messages.length);
console.log('💬 Direct message:', !!directMessage);

// Extract conversation components
let assistantStart = '';
let userMessage = '';

// Handle both structured messages and direct message input
if (directMessage) {
  userMessage = directMessage;
  assistantStart = "I'm here to listen and support you. How are you feeling today?";
} else {
  for (const msg of messages) {
    if (msg.role === 'assistant' && msg.turn === 1) {
      assistantStart = msg.content;
    }
    if (msg.role === 'user' && msg.turn === 2) {
      userMessage = msg.content;
    }
  }
}

// Fallbacks
if (!assistantStart) assistantStart = "I'm here to listen and support you. How are you feeling today?";
if (!userMessage) {
  userMessage = 'Hello, I could use some support today.';
}

console.log('🤖 Assistant start:', assistantStart.substring(0, 50) + '...');
console.log('👤 User message length:', userMessage.length);

// Enhanced message analysis for EMA preparation
const messageAnalysis = {
  word_count: userMessage.split(/\s+/).length,
  contains_negative_sentiment: /doesn\'t.*(?:fix|help|work)|tired.*of|nothing.*(?:feels|seems).*(?:right|fine)|pretending.*fine.*not/i.test(userMessage),
  contains_resistance: /(?:listening|talking).*doesn\'t.*(?:fix|help)|people.*say.*like.*magical|before.*you.*say|not.*in.*the.*mood/i.test(userMessage),
  emotional_intensity: userMessage.includes('*') || userMessage.split('...').length > 2 || userMessage.includes('!!!') ? 'high' : 'moderate',
  preliminary_analysis: true,
  conversation_turn: turnIndex
};

// Prepare enhanced result with Phase 1 enhancements
const result = {
  // Core session data
  session_id: sessionId,
  turn_index: turnIndex,
  clean_msg: userMessage,
  assistant_start: assistantStart,
  evaluation_mode: evaluationMode,
  api_request: apiRequest,

  // Conversation context for personality detection
  conversation_context: `assistant: ${assistantStart}\nuser: ${userMessage}`,

  // Enhanced message analysis
  message_analysis: messageAnalysis,

  // Phase 1 preparation flags
  phase1_enhancements: {
    ema_smoothing_ready: true,
    verification_enabled: true,
    database_persistence: true,
    webhook_api_enabled: apiRequest,
    webhook_method_fixed: true
  },

  // Raw messages array for reference
  messages: messages,

  // Timestamps
  ingested_at: new Date().toISOString(),

  // Initialize pipeline state objects (will be populated by subsequent nodes)
  detector: {
    raw_response: null,
    api_status: 'pending',
    ema_ready: true
  },
  regulator: {
    raw_directives: null,
    zurich_applied: false
  },
  generator: {
    raw_response: null,
    api_status: 'pending'
  },
  verifier: {
    verification_status: 'pending',
    refinement_needed: false
  },
  database: {
    persistence_status: 'pending'
  }
};

console.log('✅ Enhanced ingest completed - ready for EMA smoothing');

return [{ json: result }];

// Merge loaded personality state with input data
const allInputs = $input.all();

console.log('🔄 MERGE STATE - Total inputs:', allInputs.length);

// Identify which input is from Enhanced Ingest vs PostgreSQL
// Enhanced Ingest has: session_id, clean_msg, conversation_context
// PostgreSQL has: ocean_o, ocean_c, ocean_e, etc.
let inputData = {};
let dbResults = [];

for (const input of allInputs) {
  const data = input?.json;
  if (!data) continue;

  // Check if this is Enhanced Ingest data (has conversation_context, which is unique to ingest)
  // Note: session_id might be empty string before fix, so check conversation_context instead
  if (data.conversation_context !== undefined) {
    inputData = data;
    console.log('✅ Found Enhanced Ingest data (session_id:', data.session_id || 'MISSING', ')');
  }
  // Check if this is PostgreSQL data (has ocean_o, ocean_c fields)
  else if (data.ocean_o !== undefined || (Array.isArray(data) && data[0]?.ocean_o !== undefined)) {
    // Handle array or single object
    if (Array.isArray(data)) {
      dbResults = data;
    } else {
      dbResults = [data];
    }
    console.log('✅ Found PostgreSQL data');
  }
  // Check for wrapped format { data: [...] }
  else if (data.data && Array.isArray(data.data)) {
    dbResults = data.data;
    console.log('✅ Found PostgreSQL data (wrapped)');
  }
}

// Fallback: if we didn't identify correctly, use order-based approach
if (!inputData.conversation_context && allInputs.length > 0) {
  console.log('⚠️ Using fallback - assuming first input is Enhanced Ingest');
  inputData = allInputs[0]?.json || {};
}

console.log('🔄 MERGE STATE - DB Results found:', dbResults.length);
if (dbResults.length > 0) {
  console.log('🔄 MERGE STATE - DB result keys:', Object.keys(dbResults[0]).slice(0, 5).join(', '));
}

let previousOcean = { O: 0, C: 0, E: 0, A: 0, N: 0 };
let previousConfidence = { O: 0.5, C: 0.5, E: 0.5, A: 0.5, N: 0.5 };
let previousTurnIndex = 0;
let previousStable = false;

if (dbResults.length > 0) {
  const state = dbResults[0];
  previousOcean = {
    O: state.ocean_o || 0,
    C: state.ocean_c || 0,
    E: state.ocean_e || 0,
    A: state.ocean_a || 0,
    N: state.ocean_n || 0
  };
  previousConfidence = {
    O: state.confidence_o || 0.5,
    C: state.confidence_c || 0.5,
    E: state.confidence_e || 0.5,
    A: state.confidence_a || 0.5,
    N: state.confidence_n || 0.5
  };
  previousTurnIndex = state.turn_index || 0;
  previousStable = state.stable || false;

  console.log('✅ Loaded previous state from turn:', previousTurnIndex);
  console.log('✅ Previous OCEAN:', JSON.stringify(previousOcean));
  console.log('✅ Previous stable:', previousStable);
} else {
  console.log('📝 No previous state found - starting fresh');
}

// IMPORTANT: Merge previous_state into inputData, not the other way around!
const result = {
  ...inputData,  // This should be Enhanced Ingest data
  previous_state: {
    ocean: previousOcean,
    confidence: previousConfidence,
    turn_index: previousTurnIndex,
    stable: previousStable,
    loaded_from_db: dbResults.length > 0
  }
};

// Verify we're returning the right data
if (!result.session_id) {
  console.log('❌ ERROR: Result missing session_id! Input data was wrong.');
  console.log('❌ inputData keys:', Object.keys(inputData).join(', '));
} else {
  console.log('✅ Merge complete - session_id:', result.session_id);
  console.log('✅ Previous state attached, loaded_from_db:', result.previous_state.loaded_from_db);
}

return [{ json: result }];

// PHASE 1: PERSONALITY DETECTION WITH EMA SMOOTHING - ACTUAL IMPLEMENTATION
// Detects OCEAN personality traits and applies EMA smoothing for stability

const inputData = $input.first().json;
const sessionId = inputData.session_id;
const turnIndex = inputData.turn_index || 1;
const conversationContext = inputData.conversation_context || '';
const userMessage = inputData.clean_msg || '';

console.log('🧠 PERSONALITY DETECTION - Turn:', turnIndex);
console.log('📝 Context length:', conversationContext.length);

// ZURICH MODEL Detection Prompt - Continuous Values
const detectionPrompt = `Analyze the following conversation using the Zurich Model framework for personality assessment. Evaluate the user's Big Five traits by examining their underlying motivational needs for SECURITY, AROUSAL, and POWER, along with their coping strategies and approach-avoidance patterns.

**ASSESSMENT FRAMEWORK:**

**Openness (Arousal System):**
Examine the user's need for cognitive and experiential arousal:
• HIGH (>0.5): Seeks novelty, cognitive stimulation, new perspectives; shows curiosity about possibilities; embraces uncertainty as stimulating
• LOW (<-0.5): Prefers familiar patterns; avoids cognitive overload; finds comfort in routine; shows resistance to new ideas that disrupt mental equilibrium
• NEUTRAL (-0.5 to 0.5): Balanced or no clear preference pattern evident

**Conscientiousness (Security & Control System):**
Assess need for structure, predictability, and behavioral control:
• HIGH (>0.5): Seeks security through organization and planning; shows systematic approach to problems; values reliability and achievement as sources of stability
• LOW (<-0.5): Prefers flexible, spontaneous adaptation; avoids rigid structures; shows accommodative coping (adjusting goals rather than pursuing them systematically)
• NEUTRAL (-0.5 to 0.5): Balanced or no clear organizational preference evident

**Extraversion (Social Arousal & Power System):**
Evaluate approach vs. avoidance in social energy and stimulation seeking:
• HIGH (>0.5): Approaches social situations for stimulation; seeks social influence and connection; energized by interpersonal engagement
• LOW (<-0.5): Avoids high-stimulation social environments; prefers controlled, low-intensity social contact; seeks solitude for regulation
• NEUTRAL (-0.5 to 0.5): Balanced or no clear social energy pattern evident

**Agreeableness (Affiliation & Security System):**
Analyze approach vs. avoidance in interpersonal bonding and cooperation:
• HIGH (>0.5): Approaches others with trust and empathy; seeks harmony and mutual support; prioritizes group cohesion over individual goals
• LOW (<-0.5): Shows skepticism toward others' motives; maintains psychological distance; prioritizes autonomy over conformity; shows competitive rather than cooperative tendencies
• NEUTRAL (-0.5 to 0.5): Balanced or no clear interpersonal orientation evident

**Neuroticism (Security & Threat Detection System):**
Evaluate emotional regulation and security maintenance (INVERTED SCORING):
• HIGH NEUROTICISM (<-0.5): Shows heightened threat sensitivity; experiences emotional instability; difficulty maintaining psychological security; uses worry/anxiety as coping mechanisms
• LOW NEUROTICISM (>0.5): Maintains emotional equilibrium; shows secure baseline; effective emotional regulation; calm under stress
• NEUTRAL (-0.5 to 0.5): Balanced emotional regulation

**CONTEXTUAL FACTORS TO CONSIDER:**
- Coping strategies: Are they problem-focused (assimilative) or acceptance-focused (accommodative)?
- Social context: How does the therapeutic/support context influence their behavior?
- Dynamic patterns: Do they show consistent patterns or situational variability?
- Motivational conflicts: Are there competing needs creating internal tension?

**INSTRUCTIONS:**
Focus on BEHAVIORAL MANIFESTATIONS of underlying motivational systems rather than surface descriptions. Look for approach-avoidance patterns, need satisfaction strategies, and dynamic adaptations. Consider how the person regulates their distance from others and manages their core needs for security, arousal, and power.

Return continuous values from -1.0 to +1.0. Use intermediate values to reflect degree/intensity of patterns.

Return only JSON format: {"ocean":{"O":float,"C":float,"E":float,"A":float,"N":float}, "confidence":{"O":float,"C":float,"E":float,"A":float,"N":float}, "evidence_quotes":[string,...]}

Values in [-1,1], confidence in [0,1]. No additional commentary.

Conversation:
${conversationContext}`;

// Call personality detection API
const apiUrl = 'https://api.nuwaapi.com/v1/chat/completions';
const apiKey = 'sk-YhJ5ZEcfTRcDJyPpcX2O26T6ShXRF6vsS9t4vUwOVtuQw4mz';

const options = {
  method: 'POST',
  url: apiUrl,
  headers: {
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${apiKey}`
  },
  body: JSON.stringify({
    model: 'gpt-4',
    messages: [{ role: 'user', content: detectionPrompt }],
    max_tokens: 500,
    temperature: 0.3
  }),
  timeout: 15000
};

try {
  const response = await this.helpers.httpRequest(options);

  if (response.choices && response.choices.length > 0) {
    const content = response.choices[0].message.content.trim();
    console.log('🎯 Detection response:', content.substring(0, 100));

    // Parse JSON response with nested ocean format (B2-1)
    let detectedTraits;
    try {
      detectedTraits = JSON.parse(content);
    } catch (parseError) {
      console.log('⚠️ JSON parse error, using fallback');
      detectedTraits = {
        ocean: { O: 0, C: 0, E: 0, A: 0, N: 0 },
        confidence: { O: 0.3, C: 0.3, E: 0.3, A: 0.3, N: 0.3 },
        evidence_quotes: []
      };
    }

    // Extract ocean values from nested structure (B2-1 format)
    const currentOcean = detectedTraits.ocean || detectedTraits; // fallback for old format
    const currentConfidence = detectedTraits.confidence || {};

    // EMA Smoothing Implementation
    const EMA_ALPHA = 0.3;
    const STABILIZATION_THRESHOLD = 5;

    // Load previous state from database (merged in previous node)
    const previousState = inputData.previous_state || { ocean: {}, confidence: {}, loaded_from_db: false };
    const previousOcean = previousState.ocean || { O: 0, C: 0, E: 0, A: 0, N: 0 };
    const previousConfidence = previousState.confidence || { O: 0.5, C: 0.5, E: 0.5, A: 0.5, N: 0.5 };
    console.log('📊 Using previous state from DB:', previousState.loaded_from_db);

    // Apply EMA smoothing
    const smoothedOcean = {};
    const smoothedConfidence = {};

    ['O', 'C', 'E', 'A', 'N'].forEach(trait => {
      const currentValue = currentOcean[trait] || 0;
      const currentConf = currentConfidence[trait] || 0.5;

      if (turnIndex === 1) {
        smoothedOcean[trait] = currentValue;
        smoothedConfidence[trait] = currentConf;
      } else {
        smoothedOcean[trait] = EMA_ALPHA * currentValue + (1 - EMA_ALPHA) * (previousOcean[trait] || 0);
        smoothedConfidence[trait] = EMA_ALPHA * currentConf + (1 - EMA_ALPHA) * (previousConfidence[trait] || 0.5);
      }
    });

    // Determine if personality is stable
    const personalityStable = turnIndex >= STABILIZATION_THRESHOLD && 
                              Object.values(smoothedConfidence).every(conf => conf >= 0.6);

    console.log('✅ Detection successful with EMA smoothing');
    console.log('🎯 Personality stable:', personalityStable);

    const updatedDetector = {
      raw_response: response,
      current_detection: detectedTraits,
      ocean_detected: currentOcean,  // Extracted ocean values
      smoothed_ocean: smoothedOcean,
      current_confidence: currentConfidence,  // Extracted confidence
      smoothed_confidence: smoothedConfidence,
      personality_stable: personalityStable,
      ema_applied: true,
      ema_alpha: EMA_ALPHA,
      stabilization_turns: STABILIZATION_THRESHOLD,
      turn_number: turnIndex,
      api_status: 'success',
      evidence_quotes: detectedTraits.evidence_quotes || [],
      format_used: 'b2-1-nested-ocean',
      timestamp: new Date().toISOString()
    };

    const result = {
      ...inputData,
      detector: updatedDetector,
      ocean_disc: smoothedOcean // Legacy compatibility
    };

    return [{ json: result }];

  } else {
    throw new Error('No choices in detection response');
  }

} catch (error) {
  console.log('❌ Detection error:', error.message);

  // Fallback with neutral personality
  const fallbackOcean = { O: 0, C: 0, E: 0, A: 0, N: 0 };
  const fallbackConfidence = { O: 0.3, C: 0.3, E: 0.3, A: 0.3, N: 0.3 };

  const result = {
    ...inputData,
    detector: {
      api_status: 'error',
      error: error.message,
      smoothed_ocean: fallbackOcean,
      smoothed_confidence: fallbackConfidence,
      personality_stable: false,
      ema_applied: false,
      timestamp: new Date().toISOString()
    },
    ocean_disc: fallbackOcean
  };

  return [{ json: result }];
}

// ENHANCED ZURICH MODEL REGULATION WITH EMA INTEGRATION - IMPLEMENTED
// Maps smoothed personality estimates to behavioral directives

const inputData = $input.first()?.json || {};
const detectorData = inputData.detector || {};

// Use EMA-smoothed personality estimates if available, fall back to raw detection
const oceanState = detectorData.smoothed_ocean || detectorData.ocean_detected || inputData.ocean_disc || { O:0,C:0,E:0,A:0,N:0 };
const confidenceScores = detectorData.smoothed_confidence || detectorData.current_confidence || {};
const personalityStable = detectorData.personality_stable || false;

// Get session_id and message from the correct place in the data structure
const sessionId = inputData.session_id || $input.first()?.json?.session_id || '';
const turnText = inputData.clean_msg || $input.first()?.json?.clean_msg || '';
const turnIndex = inputData.turn_index || $input.first()?.json?.turn_index || 1;

console.log('🎯 ENHANCED REGULATION - Using', personalityStable ? 'stable' : 'evolving', 'personality state');
console.log('🧠 EMA-smoothed OCEAN:', JSON.stringify(oceanState));

// Enhanced Trait-to-Prompt Mappings with confidence weighting
const PROMPT_MAP = {
  O: {
    1: 'Invite exploration and novelty',
    '-1': 'Focus on familiar topics; reduce novelty'
  },
  C: {
    1: 'Provide organized, structured guidance',
    '-1': 'Keep the demeanour flexible, relaxed, and spontaneous'
  },
  E: {
    1: 'Maintain an energetic, sociable tone',
    '-1': 'Adopt a calm, low-key style with reflective space'
  },
  A: {
    1: 'Show warmth, empathy, and collaboration',
    '-1': 'Use a neutral, matter-of-fact stance; limit personal bonding'
  },
  N: {
    1: 'Reassure stability and confidence',
    '-1': 'Offer extra comfort; acknowledge anxieties'
  }
};

function buildEnhancedDirectives(oceanValues, confidenceValues, isStable) {
  const directives = [];
  const mappingDetails = [];
  const MIN_CONFIDENCE = 0.4; // Lowered for more directive coverage

  ['O', 'C', 'E', 'A', 'N'].forEach(trait => {
    const value = oceanValues[trait] || 0;
    const confidence = confidenceValues[trait] || 0.5;

    // Determine directive based on trait value
    let direction = 0;
    if (value > 0.2) direction = 1;
    else if (value < -0.2) direction = -1;

    // Apply directive only if trait value is significant and confidence is sufficient
    if (direction !== 0 && (confidence >= MIN_CONFIDENCE || isStable)) {
      const prompt = PROMPT_MAP[trait][direction.toString()];
      if (prompt) {
        // Weight directive by confidence if personality is not yet stable
        const weightedPrompt = isStable ? prompt : `${prompt} (confidence: ${confidence.toFixed(2)})`;
        directives.push(weightedPrompt);
        mappingDetails.push({
          trait: trait,
          value: value,
          confidence: confidence,
          directive: prompt,
          weighted: !isStable,
          timestamp: new Date().toISOString()
        });
      }
    } else if (direction !== 0) {
      console.log(`⚠️ Skipping ${trait} directive due to low confidence: ${confidence.toFixed(2)}`);
    }
  });

  return { directives, mappingDetails };
}

const regulationResult = buildEnhancedDirectives(oceanState, confidenceScores, personalityStable);
const directives = regulationResult.directives;
const mappingDetails = regulationResult.mappingDetails;

// Ensure at least one basic directive
if (directives.length === 0) {
  directives.push('Provide supportive, empathetic responses');
}

console.log('🎯 Enhanced Regulation Directives:', directives.length);
console.log('📊 Confidence-weighted mappings:', mappingDetails.length);

// Enhanced analysis
const analysis = {
  total_directives: directives.length,
  confidence_filtered: mappingDetails.filter(m => m.confidence >= 0.6).length,
  personality_stable: personalityStable,
  ema_enhanced: detectorData.ema_applied || false,
  regulation_strategy: personalityStable ? 'stable_personality' : 'evolving_personality'
};

// Update regulator object with enhanced data
const updatedRegulator = {
  raw_directives: directives,
  raw_analysis: analysis,
  raw_mapping_details: mappingDetails,
  enhanced_prompt_map: PROMPT_MAP,
  zurich_applied: true,
  confidence_weighted: !personalityStable,
  regulation_status: 'success',
  input_ocean: oceanState,
  input_confidence: confidenceScores,
  directive_count: directives.length,
  timestamp: new Date().toISOString()
};

const result = {
  ...inputData,
  regulator: updatedRegulator,
  directives: directives, // Legacy compatibility
  ocean_disc: oceanState,
  session_id: sessionId,
  turn_text: turnText
};

console.log('✅ Enhanced regulation completed');

return [{ json: result }];

// ENHANCED RESPONSE GENERATION WITH PHASE 1 IMPROVEMENTS - IMPLEMENTED
// Generates personality-aware responses using refined directives

const inputData = $input.first()?.json || {};
const directives = inputData?.directives || [];
const sessionId = inputData?.session_id || '';
const turnText = inputData?.turn_text || '';
const oceanDisc = inputData?.ocean_disc || { O:0, C:0, E:0, A:0, N:0 };
const personalityStable = inputData.detector?.personality_stable || false;
const confidenceScores = inputData.detector?.smoothed_confidence || {};

let userText = turnText.trim();
if (!userText) {
  userText = 'Please provide a supportive reply.';
}

// Enhanced system prompt with Phase 1 improvements
const enhancedSystemPrompt = [
  'You are a supportive assistant with advanced personality adaptation capabilities.',
  `Follow these behavior directives strictly: ${JSON.stringify(directives)}`,
  personalityStable ? 
    'The user\'s personality profile is now stable - maintain consistent adaptation.' :
    'The user\'s personality is still being refined - be especially attentive to their responses.',
  'Constraints: stay grounded in the user text only; 1-2 questions max; 70-150 words.',
  'Your response will be automatically verified for directive adherence.'
].join(' ');

const fullPrompt = `${enhancedSystemPrompt}\n\nUser: ${userText}`;

console.log('🚀 Enhanced Generation - Personality stable:', personalityStable);
console.log('📝 Using directives:', directives.length);
console.log('👤 User text length:', userText.length);

const apiUrl = 'https://api.nuwaapi.com/v1/chat/completions';
const apiKey = 'sk-YhJ5ZEcfTRcDJyPpcX2O26T6ShXRF6vsS9t4vUwOVtuQw4mz';

const options = {
  method: 'POST',
  url: apiUrl,
  headers: { 
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${apiKey}`
  },
  body: JSON.stringify({
    model: 'gpt-4',
    messages: [{ role: 'user', content: fullPrompt }],
    max_tokens: 220,
    temperature: personalityStable ? 0.6 : 0.7 // More stable responses for stable personalities
  }),
  timeout: 20000
};

try {
  const response = await this.helpers.httpRequest(options);

  if (response.choices && response.choices.length > 0) {
    const content = response.choices[0].message.content;
    console.log('✅ Enhanced generation successful');
    console.log('📝 Generated content length:', content.length);

    // Enhanced generator object
    const updatedGenerator = {
      raw_response: response,
      raw_content: content,
      system_prompt: enhancedSystemPrompt,
      full_prompt: fullPrompt,
      directives_applied: directives,
      confidence_scores: confidenceScores,
      personality_stable: personalityStable,
      user_input: userText,
      generation_config: {
        temperature: personalityStable ? 0.6 : 0.7,
        max_tokens: 220,
        model: 'gpt-4'
      },
      api_status: 'success',
      phase1_enhanced: true,
      ready_for_verification: true,
      timestamp: new Date().toISOString()
    };

    const result = {
      ...inputData,
      generator: updatedGenerator,
      choices: [{ message: { content } }], // Legacy compatibility
      session_id: sessionId,
      turn_text: turnText,
      ocean_disc: oceanDisc,
      directives: directives,
      api_used: 'gpt-4-enhanced',
      status: 'success'
    };

    return [{ json: result }];
  } else {
    console.log('❌ No choices in enhanced generation response');

    const errorResult = {
      ...inputData,
      generator: {
        api_status: 'no_choices',
        error: 'No choices in API response',
        phase1_enhanced: true,
        timestamp: new Date().toISOString()
      },
      choices: [{ message: { content: 'I understand you need support. Let me help you work through this.' } }],
      error: 'No choices in response'
    };

    return [{ json: errorResult }];
  }

} catch (error) {
  console.log('❌ Enhanced generation error:', error.message);

  const errorResult = {
    ...inputData,
    generator: {
      api_status: 'error',
      error: error.message,
      phase1_enhanced: true,
      timestamp: new Date().toISOString()
    },
    choices: [{ message: { content: 'I\'m here to support you. Please tell me more about what you\'re experiencing.' } }],
    error: error.message
  };

  return [{ json: errorResult }];
}

// VERIFICATION & REFINEMENT PIPELINE - IMPLEMENTED
// Verifies directive adherence and refines responses when needed

const inputData = $input.first()?.json || {};
const generatorData = inputData.generator || {};
const draftReply = generatorData.raw_content || inputData.choices?.[0]?.message?.content || 'No response generated';
const directives = inputData.directives || [];
const conversationContext = inputData.conversation_context || '';

console.log('🔍 VERIFICATION - Checking directive adherence');
console.log('📝 Draft reply length:', draftReply.length);
console.log('🎯 Directives to verify:', directives.length);

// Basic verification criteria
const verificationResults = {
  adherence_score: 0.8, // Default good score
  issues_identified: [],
  criterion_scores: {},
  refinement_needed: false,
  verification_status: 'verified'
};

// Check basic constraints
const questionCount = (draftReply.match(/\?/g) || []).length;
if (questionCount > 2) {
  verificationResults.issues_identified.push(`Too many questions (${questionCount}), should be ≤2`);
  verificationResults.adherence_score -= 0.1;
}

const wordCount = draftReply.split(/\s+/).length;
if (wordCount < 30 || wordCount > 200) {
  verificationResults.issues_identified.push(`Word count ${wordCount} outside 30-200 range`);
  verificationResults.adherence_score -= 0.1;
}

// Check for grounding (basic heuristics)
const novelClaimIndicators = [
  'research shows', 'studies indicate', 'experts say', 'according to',
  'it is known that', 'science shows', 'data suggests', 'statistics show'
];

for (const indicator of novelClaimIndicators) {
  if (draftReply.toLowerCase().includes(indicator)) {
    verificationResults.issues_identified.push(`Potential novel claim detected: "${indicator}"`);
    verificationResults.adherence_score -= 0.2;
  }
}

// Determine if refinement is needed
verificationResults.refinement_needed = verificationResults.adherence_score < 0.6;

let finalResponse = draftReply;
let refinementAttempts = 0;

// Apply refinement if needed
if (verificationResults.refinement_needed) {
  console.log('⚠️ Refinement needed, applying fixes...');

  // Simple refinement: remove novel claims and excess questions
  finalResponse = draftReply.replace(/research shows|studies indicate|experts say|according to/gi, 'from my understanding');

  // Limit questions
  const sentences = finalResponse.split(/[.!]/);
  const questionSentences = sentences.filter(s => s.includes('?'));
  if (questionSentences.length > 2) {
    finalResponse = sentences.slice(0, -Math.max(0, questionSentences.length - 2)).join('.') + '.';
  }

  refinementAttempts = 1;
  verificationResults.adherence_score = Math.min(0.8, verificationResults.adherence_score + 0.2);
  verificationResults.verification_status = 'refined';

  console.log('✅ Refinement applied');
} else {
  verificationResults.verification_status = 'verified';
  console.log('✅ Verification passed without refinement');
}

// Create verifier object
const updatedVerifier = {
  verification_status: verificationResults.verification_status,
  adherence_score: verificationResults.adherence_score,
  refinement_applied: refinementAttempts > 0,
  refinement_attempts: refinementAttempts,
  issues_identified: verificationResults.issues_identified,
  criterion_scores: {
    grounding: verificationResults.adherence_score,
    question_count: questionCount <= 2 ? 1.0 : 0.5,
    word_count: (wordCount >= 30 && wordCount <= 200) ? 1.0 : 0.7,
    directive_adherence: 0.8 // Placeholder - would require more sophisticated checking
  },
  verified_response: finalResponse,
  original_response: draftReply,
  verification_details: {
    question_count: questionCount,
    word_count: wordCount,
    novel_claims_detected: verificationResults.issues_identified.filter(i => i.includes('novel claim')).length
  },
  timestamp: new Date().toISOString()
};

const result = {
  ...inputData,
  verifier: updatedVerifier,
  choices: [{ message: { content: finalResponse } }] // Update with verified response
};

console.log('✅ Verification completed:', verificationResults.verification_status);

return [{ json: result }];

